// ── STEP 1: Extract text from PDF attachment ──
// Full code in: src/1_extract_pdf.js

const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});
const pdfKey = binaryKeys.find(k =>
  (item.binary[k].mimeType || '').includes('pdf') ||
  (item.binary[k].fileName || '').toLowerCase().endsWith('.pdf')
) || binaryKeys[0];

if (!pdfKey) {
  return [{ json: { error: 'No attachment found', skip: true } }];
}

const attachment = item.binary[pdfKey];
const buffer = await this.helpers.getBinaryDataBuffer(item, pdfKey);

let extractedText = '';
try {
  const raw = buffer.toString('latin1');
  const textBlocks = raw.match(/BT[\s\S]*?ET/g) || [];
  if (textBlocks.length > 0) {
    extractedText = textBlocks.join(' ')
      .replace(/\b(Td|Tm|Tf|Tj|TJ|Tr|Ts|Tw|Tc|BT|ET|rg|RG|cm|Do|q|Q)\b/g, ' ')
      .replace(/\[|\]|\(|\)/g, ' ')
      .replace(/\\\d{3}/g, '')
      .replace(/[^\x20-\x7E\n]/g, ' ')
      .replace(/\s{2,}/g, ' ').trim();
  }
  if (extractedText.length < 80) {
    extractedText = raw.replace(/[^\x20-\x7E\n]/g, ' ').replace(/\s{2,}/g, ' ').trim().substring(0, 4000);
  }
} catch (e) {
  extractedText = `[PDF extraction error: ${e.message}]`;
}

return [{ json: {
  text: extractedText.substring(0, 4000),
  filename: attachment.fileName || 'invoice.pdf',
  email_id: item.json.id || '',
  email_subject: item.json.subject || '',
  email_from: item.json.from || ''
}}];

// ── STEP 2: Build OpenAI API payload ──
// Full code in: src/2_build_prompt.js

const { text, filename, email_subject, email_from, email_id } = $input.first().json;

const systemPrompt = `You are an invoice data extraction specialist. Extract structured data from the invoice text and return ONLY valid JSON. No explanation, no markdown.

Return this schema:
{
  "vendor": "Company name",
  "invoice_number": "Invoice ID",
  "date": "YYYY-MM-DD",
  "due_date": "YYYY-MM-DD or null",
  "amount": 0,
  "currency": "USD",
  "tax": 0,
  "line_items": [{"description": "", "quantity": 1, "unit_price": 0, "amount": 0}],
  "payment_method": "Unknown",
  "notes": null
}
Rules: missing strings = null, missing numbers = 0, dates in YYYY-MM-DD.`;

return [{ json: {
  email_id, filename, email_subject, email_from,
  body: {
    model: 'gpt-4o',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: `Invoice: ${filename}
From: ${email_from}
Subject: ${email_subject}

${text}

Return JSON only.` }
    ],
    temperature: 0.1,
    max_tokens: 800,
    response_format: { type: 'json_object' }
  }
}}];

// ── STEP 3: Parse OpenAI response ──
// Full code in: src/3_parse_invoice.js

const response = $input.first().json;
const rawContent = response?.choices?.[0]?.message?.content || '';

let invoice = {};
try {
  invoice = JSON.parse(rawContent);
} catch (e) {
  const match = rawContent.match(/\{[\s\S]*\}/);
  try { invoice = match ? JSON.parse(match[0]) : {}; } catch { invoice = {}; }
}

const prev = $('Build OpenAI Payload').first().json;

const clean = {
  vendor:         String(invoice.vendor         || 'Unknown').trim(),
  invoice_number: String(invoice.invoice_number || 'N/A').trim(),
  date:           String(invoice.date           || new Date().toISOString().split('T')[0]).trim(),
  due_date:       invoice.due_date ? String(invoice.due_date).trim() : null,
  amount:         parseFloat(invoice.amount)  || 0,
  currency:       String(invoice.currency     || 'USD').trim().toUpperCase(),
  tax:            parseFloat(invoice.tax)     || 0,
  line_items:     Array.isArray(invoice.line_items) ? invoice.line_items.slice(0, 10) : [],
  payment_method: String(invoice.payment_method || 'Unknown').trim(),
  notes:          invoice.notes ? String(invoice.notes).trim() : null,
  email_id:       prev.email_id      || '',
  email_subject:  prev.email_subject || '',
  email_from:     prev.email_from    || '',
  filename:       prev.filename      || '',
  processed_at:   new Date().toISOString(),
};

return [{ json: clean }];

// ── STEP 4: Anomaly detection ──
// Full code in: src/4_anomaly_detector.js

const inv = $input.first().json;
const anomalies = [];

if (inv.amount > 10000) anomalies.push(`High amount: ${inv.currency} ${inv.amount.toFixed(2)}`);
if (inv.amount <= 0) anomalies.push(`Invalid amount: ${inv.amount}`);
if (!inv.vendor || inv.vendor === 'Unknown') anomalies.push('Vendor name could not be extracted');
if (!inv.invoice_number || inv.invoice_number === 'N/A') anomalies.push('Invoice number missing');

if (inv.date) {
  const d = new Date(inv.date), today = new Date();
  today.setHours(0,0,0,0);
  if (!isNaN(d) && d > today) anomalies.push(`Future date: ${inv.date}`);
}

if (inv.due_date) {
  const due = new Date(inv.due_date), today = new Date();
  if (!isNaN(due) && due < today) {
    const days = Math.floor((today - due) / 86400000);
    anomalies.push(`Overdue by ${days} day(s) — due: ${inv.due_date}`);
  }
}

if (inv.tax > 0 && inv.amount > 0 && inv.tax / inv.amount > 0.5) {
  anomalies.push(`Tax (${inv.tax}) is ${(inv.tax/inv.amount*100).toFixed(1)}% of total`);
}

if (inv.line_items?.length > 0) {
  const lineTotal = inv.line_items.reduce((s, i) => s + (parseFloat(i.amount)||0), 0);
  if (Math.abs(lineTotal - inv.amount) > 1 && lineTotal > 0) {
    anomalies.push(`Line items total (${lineTotal.toFixed(2)}) ≠ invoice total (${inv.amount})`);
  }
}

return [{ json: {
  ...inv,
  has_anomaly:     anomalies.length > 0,
  anomaly_count:   anomalies.length,
  anomalies,
  anomaly_summary: anomalies.length > 0 ? anomalies.join(' | ') : 'Clean'
}}];
